    requiredDocuments:['طلب الحصول على نصوب حرجية وتزيينية.'],
    fees:'طابع مالي بقيمة 1000 ل.ل.',
    processingTime:'فوراً | فوراً | يوم واحد | 3 – 4 أيام',
    steps:['يقدم الطلب إما إلى:','قلم المصلحة الإقليمية الذي يحوله إلى رئيس المصلحة الذي يوافق على الطلب.','قلم مديرية الثروة الزراعية الذي يرفعه إلى مدير الثروة الزراعية الذي يحوله إلى رئيس مصلحة البستنة والمحاصيل الحقلية ويكون التوقيع وفقاً للعدد.','ضمن 25 نصبة: رئيس المصلحة.','ضمن 75 نصبة: المدير العام.','إذا زاد العدد عن 75 نصبة: الوزير.'],
